package com.example.mobilefinalproject

import android.app.Application
import com.squareup.picasso.OkHttp3Downloader
import com.squareup.picasso.Picasso
import okhttp3.Cache
import okhttp3.OkHttpClient
import java.io.File

/**
 * Custom Application class.
 * Configures Picasso with a persistent OkHttp disk cache (50 MB) so remote images
 * survive network interruptions and app restarts without any extra code in UI layer.
 */
class AppApplication : Application() {

    override fun onCreate() {
        super.onCreate()
        configurePicasso()
    }

    private fun configurePicasso() {
        val cacheDir = File(cacheDir, "picasso-cache")
        val diskCacheSizeBytes = 50L * 1024 * 1024 // 50 MB

        val okHttpClient = OkHttpClient.Builder()
            .cache(Cache(cacheDir, diskCacheSizeBytes))
            .build()

        val picasso = Picasso.Builder(this)
            .downloader(OkHttp3Downloader(okHttpClient))
            .build()

        // setSingletonInstance throws if called more than once (e.g. some test setups).
        runCatching { Picasso.setSingletonInstance(picasso) }
    }
}

package com.example.mobilefinalproject.cache

import android.content.Context
import android.graphics.drawable.ColorDrawable
import android.widget.ImageView
import com.example.mobilefinalproject.R
import com.example.mobilefinalproject.db.AppDatabase
import com.example.mobilefinalproject.db.entity.CachedImageEntity
import com.example.mobilefinalproject.session.TokenManager
import com.squareup.picasso.Picasso
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import okhttp3.OkHttpClient
import okhttp3.Request
import java.io.File
import java.util.concurrent.TimeUnit

/**
 * Manages a persistent local image cache on disk, tracked by Room.
 *
 * ## How it works
 * 1. `loadInto` loads an image into an ImageView. It first checks Room/disk for a
 *    cached copy and loads that immediately (no network, no placeholder flash).
 *    In the background it re-downloads the remote URL so the disk copy stays current.
 * 2. When no cached copy exists, Picasso fetches from network. A placeholder is shown
 *    only if the ImageView is currently empty; otherwise the current image is kept
 *    while the new one loads (prevents the "green icon flash" on teal background).
 * 3. `invalidate` removes a URL from Room + disk + Picasso memory cache — call this
 *    before loading a URL whose content has changed (e.g. after a profile photo update).
 * 4. `evictStale` prunes entries older than a given age (default 7 days).
 *
 * Auth note: `saveToCache` uses an OkHttpClient with the app's Bearer token so that
 * images served from authenticated endpoints are downloaded correctly.
 * Picasso itself is also configured with auth in AppApplication.
 */
class ImageCacheManager(private val context: Context) {

    private val dao = AppDatabase.getInstance(context).cachedImageDao()
    private val cacheDir: File
        get() = File(context.filesDir, "img_cache").also { it.mkdirs() }

    /** Authenticated OkHttpClient used for disk-cache downloads. */
    private val httpClient: OkHttpClient by lazy {
        OkHttpClient.Builder()
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .addInterceptor { chain ->
                val token = TokenManager.getAccessToken(context)
                val request = if (token != null) {
                    chain.request().newBuilder()
                        .header("Authorization", "Bearer $token")
                        .build()
                } else chain.request()
                chain.proceed(request)
            }
            .build()
    }

    // ── Public API ──────────────────────────────────────────────────────────

    /**
     * Loads [url] into [imageView].
     *
     * - If a local cached file exists → display it instantly (no placeholder).
     *   Refreshes the file in the background so it stays current.
     * - If no cached file → load from network via Picasso (which has auth via
     *   AppApplication). A placeholder is shown only when the ImageView is currently
     *   empty, to avoid the green-background flash when re-navigating to the screen.
     */
    suspend fun loadInto(
        url: String?,
        imageView: ImageView,
        placeholderRes: Int = R.drawable.ic_person
    ) {
        if (url.isNullOrBlank()) {
            withContext(Dispatchers.Main) { imageView.setImageResource(placeholderRes) }
            return
        }

        // ── Serve from disk cache (zero network, zero placeholder flash) ────
        val cachedFile = getCachedFile(url)
        if (cachedFile != null) {
            withContext(Dispatchers.Main) {
                Picasso.get()
                    .load(cachedFile)
                    .noPlaceholder()          // file is local – loads instantly, no flash
                    .error(placeholderRes)
                    .into(imageView)
            }
            // Keep the disk copy fresh in the background
            refreshInBackground(url)
            return
        }

        // ── No cached file: load from network ───────────────────────────────
        withContext(Dispatchers.Main) {
            val builder = Picasso.get().load(url).error(placeholderRes)
            // Show placeholder only when the view is currently empty. If the view
            // already shows something (previous image / app restoring state), keep
            // that content while the new image loads – avoids the teal-background flash.
            val isEmpty = imageView.drawable == null || imageView.drawable is ColorDrawable
            if (isEmpty) builder.placeholder(placeholderRes) else builder.noPlaceholder()
            builder.into(imageView)
        }
        // Persist for the next cold start / offline session
        saveToCache(url)
    }

    /**
     * Removes [url] from Room, deletes the local file, and invalidates Picasso's
     * in-memory cache entry. Call this after the remote content at [url] has changed
     * (e.g. after the user replaces their profile photo).
     */
    suspend fun invalidate(url: String) = withContext(Dispatchers.IO) {
        dao.get(url)?.let { entity -> File(entity.localFilePath).delete() }
        dao.delete(url)
        withContext(Dispatchers.Main) {
            runCatching { Picasso.get().invalidate(url) }
        }
    }

    /**
     * Returns the locally cached File for [url] if it exists on disk *and* in Room,
     * otherwise returns null.
     */
    suspend fun getCachedFile(url: String): File? = withContext(Dispatchers.IO) {
        val entity = dao.get(url) ?: return@withContext null
        val file = File(entity.localFilePath)
        if (file.exists()) file else {
            // Stale Room entry (file deleted externally) — remove the DB row
            dao.delete(url)
            null
        }
    }

    /**
     * Downloads [url] using an authenticated OkHttpClient and stores it on disk,
     * then records the path in Room. Returns the saved File on success, null on error.
     */
    suspend fun saveToCache(url: String): File? = withContext(Dispatchers.IO) {
        return@withContext try {
            val fileName = url.hashCode().toString().replace("-", "n") + ".jpg"
            val destFile = File(cacheDir, fileName)

            val request = Request.Builder().url(url).build()
            val response = httpClient.newCall(request).execute()
            if (!response.isSuccessful) return@withContext null

            response.body?.byteStream()?.use { input ->
                destFile.outputStream().use { output -> input.copyTo(output) }
            }

            dao.upsert(CachedImageEntity(remoteUrl = url, localFilePath = destFile.absolutePath))
            destFile
        } catch (_: Exception) {
            null
        }
    }

    /**
     * Evicts cache entries (and their local files) older than [maxAgeMs] milliseconds.
     * Safe to call periodically (e.g. on app start) — defaults to 7 days.
     */
    suspend fun evictStale(maxAgeMs: Long = TimeUnit.DAYS.toMillis(7)) =
        withContext(Dispatchers.IO) {
            val cutoff = System.currentTimeMillis() - maxAgeMs
            val stale = dao.getOlderThan(cutoff)
            stale.forEach { File(it.localFilePath).delete() }
            dao.evictOlderThan(cutoff)
        }

    // ── Private helpers ─────────────────────────────────────────────────────

    /** Silently re-download [url] to disk so the cached copy stays up-to-date. */
    private suspend fun refreshInBackground(url: String) {
        withContext(Dispatchers.IO) {
            try { saveToCache(url) } catch (_: Exception) { /* best-effort */ }
        }
    }
}

package com.example.mobilefinalproject.db
import android.content.Context import androidx.room.Database import androidx.room.Room import androidx.room.RoomDatabase import com.example.mobilefinalproject.db.dao.CachedImageDao import com.example.mobilefinalproject.db.dao.ChatMessageDao import com.example.mobilefinalproject.db.dao.ConversationDao import com.example.mobilefinalproject.db.dao.DriverProfileDao import com.example.mobilefinalproject.db.dao.OrderDao import com.example.mobilefinalproject.db.dao.UserDao import com.example.mobilefinalproject.db.entity.CachedImageEntity import com.example.mobilefinalproject.db.entity.ChatMessageEntity import com.example.mobilefinalproject.db.entity.ConversationEntity import com.example.mobilefinalproject.db.entity.DriverProfileEntity import com.example.mobilefinalproject.db.entity.OrderEntity import com.example.mobilefinalproject.db.entity.UserEntity
@Database( entities = [ OrderEntity::class, UserEntity::class, DriverProfileEntity::class, ConversationEntity::class, ChatMessageEntity::class, CachedImageEntity::class, ], version = 1, exportSchema = false ) abstract class AppDatabase : RoomDatabase() {
abstract fun orderDao(): OrderDao abstract fun userDao(): UserDao abstract fun driverProfileDao(): DriverProfileDao abstract fun conversationDao(): ConversationDao abstract fun chatMessageDao(): ChatMessageDao abstract fun cachedImageDao(): CachedImageDao
companion object { @Volatile private var INSTANCE: AppDatabase? = null
fun getInstance(context: Context): AppDatabase = INSTANCE ?: synchronized(this) { INSTANCE ?: Room.databaseBuilder( context.applicationContext, AppDatabase::class.java, "app_cache.db" ) // Allow destructive migration for development. Replace with proper // Migration objects before shipping to production. .fallbackToDestructiveMigration() .build() .also { INSTANCE = it } } } }

package com.example.mobilefinalproject.db
import com.example.mobilefinalproject.db.entity.ChatMessageEntity import com.example.mobilefinalproject.db.entity.ConversationEntity import com.example.mobilefinalproject.db.entity.DriverProfileEntity import com.example.mobilefinalproject.db.entity.OrderEntity import com.example.mobilefinalproject.db.entity.UserEntity import com.example.mobilefinalproject.network.dto.ChatMessage import com.example.mobilefinalproject.network.dto.ConversationDetail import com.example.mobilefinalproject.network.dto.ConversationSummary import com.example.mobilefinalproject.network.dto.DriverProfile import com.example.mobilefinalproject.network.dto.MessageSender import com.example.mobilefinalproject.network.dto.OrderRead import com.example.mobilefinalproject.network.dto.UserMe
// ── OrderRead ↔ OrderEntity ────────────────────────────────────────────────
fun OrderRead.toEntity(listType: String) = OrderEntity( orderId = id, listType = listType, customerId = customerId, driverId = driverId, status = status, pickupAddress = pickupAddress, pickupLat = pickupLat, pickupLng = pickupLng, dropoffAddress = dropoffAddress, dropoffLat = dropoffLat, dropoffLng = dropoffLng, cargoDescription = cargoDescription, cargoWeightKg = cargoWeightKg, notes = notes, priceCents = priceCents, currency = currency, acceptedAt = acceptedAt, startedAt = startedAt, pickedUpAt = pickedUpAt, completedAt = completedAt, cancelledAt = cancelledAt, cancellationReason = cancellationReason, cargoImageUrl = cargoImageUrl, createdAt = createdAt, updatedAt = updatedAt )
fun OrderEntity.toDto() = OrderRead( id = orderId, customerId = customerId, driverId = driverId, status = status, pickupAddress = pickupAddress, pickupLat = pickupLat, pickupLng = pickupLng, dropoffAddress = dropoffAddress, dropoffLat = dropoffLat, dropoffLng = dropoffLng, cargoDescription = cargoDescription, cargoWeightKg = cargoWeightKg, notes = notes, priceCents = priceCents, currency = currency, acceptedAt = acceptedAt, startedAt = startedAt, pickedUpAt = pickedUpAt, completedAt = completedAt, cancelledAt = cancelledAt, cancellationReason = cancellationReason, cargoImageUrl = cargoImageUrl, createdAt = createdAt, updatedAt = updatedAt )
// ── UserMe ↔ UserEntity ────────────────────────────────────────────────────
fun UserMe.toEntity() = UserEntity( id = id, fullName = fullName, role = role, profileImageUrl = profileImageUrl, createdAt = createdAt, email = email, phone = phone, isActive = isActive )
fun UserEntity.toDto() = UserMe( id = id, fullName = fullName, role = role, profileImageUrl = profileImageUrl, createdAt = createdAt, email = email, phone = phone, isActive = isActive )
// ── DriverProfile ↔ DriverProfileEntity ───────────────────────────────────
fun DriverProfile.toEntity() = DriverProfileEntity( id = id, userId = userId, licenseNumber = licenseNumber, vehicleType = vehicleType, vehiclePlate = vehiclePlate, vehicleCapacityKg = vehicleCapacityKg, status = status, currentLat = currentLat, currentLng = currentLng, lastLocationAt = lastLocationAt, rating = rating )
fun DriverProfileEntity.toDto() = DriverProfile( id = id, userId = userId, licenseNumber = licenseNumber, vehicleType = vehicleType, vehiclePlate = vehiclePlate, vehicleCapacityKg = vehicleCapacityKg, status = status, currentLat = currentLat, currentLng = currentLng, lastLocationAt = lastLocationAt, rating = rating )
// ── ConversationSummary ↔ ConversationEntity ───────────────────────────────
fun ConversationSummary.toEntity() = ConversationEntity( id = id, orderId = orderId, lastMessageBody = lastMessage?.body, lastMessageSenderId = lastMessage?.senderId, lastMessageSenderName = lastMessage?.sender?.fullName, lastMessageCreatedAt = lastMessage?.createdAt, unreadCount = unreadCount, createdAt = createdAt, updatedAt = updatedAt )
fun ConversationEntity.toSummaryDto() = ConversationSummary( id = id, orderId = orderId, lastMessage = if (lastMessageBody != null && lastMessageSenderId != null) { ChatMessage( id = 0, conversationId = id, senderId = lastMessageSenderId, sender = MessageSender( id = lastMessageSenderId, fullName = lastMessageSenderName.orEmpty() ), body = lastMessageBody, createdAt = lastMessageCreatedAt.orEmpty(), isRead = true ) } else null, unreadCount = unreadCount, createdAt = createdAt, updatedAt = updatedAt )
// ── ChatMessage ↔ ChatMessageEntity ───────────────────────────────────────
fun ChatMessage.toEntity(convId: Int) = ChatMessageEntity( id = id, conversationId = convId, senderId = senderId, senderName = sender.fullName, body = body, createdAt = createdAt, isRead = isRead )
fun ChatMessageEntity.toDto() = ChatMessage( id = id, conversationId = conversationId, senderId = senderId, sender = MessageSender(id = senderId, fullName = senderName), body = body, createdAt = createdAt, isRead = isRead )
// ── ConversationDetail helpers ─────────────────────────────────────────────
fun ConversationDetail.messageEntities() = messages.map { it.toEntity(id) }

package com.example.mobilefinalproject.db.dao

import androidx.room.Dao
import androidx.room.Insert
import androidx.room.OnConflictStrategy
import androidx.room.Query
import com.example.mobilefinalproject.db.entity.CachedImageEntity

@Dao
interface CachedImageDao {

    @Query("SELECT * FROM cached_images WHERE remoteUrl = :url")
    suspend fun get(url: String): CachedImageEntity?

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun upsert(entity: CachedImageEntity)

    @Query("DELETE FROM cached_images WHERE remoteUrl = :url")
    suspend fun delete(url: String)

    /** Remove entries older than [olderThan] millis. Caller is responsible for deleting the files. */
    @Query("SELECT * FROM cached_images WHERE cachedAt < :olderThan")
    suspend fun getOlderThan(olderThan: Long): List<CachedImageEntity>

    @Query("DELETE FROM cached_images WHERE cachedAt < :olderThan")
    suspend fun evictOlderThan(olderThan: Long)

    @Query("DELETE FROM cached_images")
    suspend fun deleteAll()
}

package com.example.mobilefinalproject.db.dao

import androidx.room.Dao
import androidx.room.Insert
import androidx.room.OnConflictStrategy
import androidx.room.Query
import androidx.room.Transaction
import com.example.mobilefinalproject.db.entity.ChatMessageEntity
import kotlinx.coroutines.flow.Flow

@Dao
interface ChatMessageDao {

    @Query("SELECT * FROM chat_messages WHERE conversationId = :conversationId ORDER BY createdAt ASC")
    fun observe(conversationId: Int): Flow<List<ChatMessageEntity>>

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun upsertAll(messages: List<ChatMessageEntity>)

    @Query("DELETE FROM chat_messages WHERE conversationId = :conversationId")
    suspend fun deleteByConversation(conversationId: Int)

    /**
     * Atomically replaces all messages for the given conversation.
     * Ensures deleted server-side messages don't linger in the local cache.
     */
    @Transaction
    suspend fun replaceConversationMessages(
        conversationId: Int,
        messages: List<ChatMessageEntity>
    ) {
        deleteByConversation(conversationId)
        if (messages.isNotEmpty()) upsertAll(messages)
    }

    @Query("DELETE FROM chat_messages WHERE cachedAt < :olderThan")
    suspend fun evictOlderThan(olderThan: Long)
}

