import android.content.Context
import com.example.mobilefinalproject.db.AppDatabase
import com.example.mobilefinalproject.db.entity.OrderEntity
import com.example.mobilefinalproject.db.toDto
import com.example.mobilefinalproject.db.toEntity
import com.example.mobilefinalproject.network.RetrofitClient
import com.example.mobilefinalproject.network.api.OrderApi
import com.example.mobilefinalproject.network.dto.OrderCancelRequest
import com.example.mobilefinalproject.network.dto.OrderCreateRequest
import com.example.mobilefinalproject.network.dto.OrderRead
import com.example.mobilefinalproject.network.dto.OrderUpdateRequest
import com.example.mobilefinalproject.network.dto.PageResponse
import com.example.mobilefinalproject.network.dto.RatingCreate
import com.example.mobilefinalproject.network.dto.RatingRead
import com.example.mobilefinalproject.network.dto.RatingResponseCreate
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.map

class OrderRepository(private val context: Context) {

    private val api: OrderApi = RetrofitClient.createService(context)
    private val dao = AppDatabase.getInstance(context).orderDao()

    // ── Reactive cache streams (Room → Flow → DTO) ────────────────────────

    /** Emits the customer's cached order history from Room — always up to date after a refresh. */
    fun observeCustomerOrders(): Flow<List<OrderRead>> =
        dao.observeByListType(OrderEntity.LIST_CUSTOMER_HISTORY)
            .map { list -> list.map { it.toDto() } }

    /** Emits cached pending (unassigned) orders for the Driver Finder screen. */
    fun observePendingOrders(): Flow<List<OrderRead>> =
        dao.observeByListType(OrderEntity.LIST_DRIVER_PENDING)
            .map { list -> list.map { it.toDto() } }

    /** Emits the driver's cached active (accepted/in-progress) orders. */
    fun observeActiveDriverOrders(): Flow<List<OrderRead>> =
        dao.observeByListType(OrderEntity.LIST_DRIVER_ACTIVE)
            .map { list -> list.map { it.toDto() } }

    /** Emits the driver's cached completed orders. */
    fun observeCompletedDriverOrders(): Flow<List<OrderRead>> =
        dao.observeByListType(OrderEntity.LIST_DRIVER_COMPLETED)
            .map { list -> list.map { it.toDto() } }

    // ── Network sync (fetch → write to Room) ──────────────────────────────

    /** Fetches customer order history from the server and updates the Room cache. */
    suspend fun refreshCustomerOrders(): ApiResult<Unit> {
        val result = safeApiCall { api.listHistory() }
        if (result is ApiResult.Success) {
            dao.replaceListType(
                OrderEntity.LIST_CUSTOMER_HISTORY,
                result.data.items.map { it.toEntity(OrderEntity.LIST_CUSTOMER_HISTORY) }
            )
        }
        return result.toUnit()
    }

    /** Fetches available orders from the server and updates the Room cache. */
    suspend fun refreshPendingOrders(): ApiResult<Unit> {
        val result = safeApiCall { api.listAvailable() }
        if (result is ApiResult.Success) {
            val pending = result.data.items.filter { it.status.lowercase() == "pending" }
            dao.replaceListType(
                OrderEntity.LIST_DRIVER_PENDING,
                pending.map { it.toEntity(OrderEntity.LIST_DRIVER_PENDING) }
            )
        }
        return result.toUnit()
    }

    /** Fetches driver active orders from the server and updates the Room cache. */
    suspend fun refreshActiveDriverOrders(): ApiResult<Unit> {
        val result = safeApiCall { api.listMyActive() }
        if (result is ApiResult.Success) {
            val active = result.data.filter {
                it.status.lowercase() in setOf("accepted", "in_progress")
            }
            dao.replaceListType(
                OrderEntity.LIST_DRIVER_ACTIVE,
                active.map { it.toEntity(OrderEntity.LIST_DRIVER_ACTIVE) }
            )
        }
        return result.toUnit()
    }

    /** Fetches driver completed orders from the server and updates the Room cache. */
    suspend fun refreshCompletedDriverOrders(): ApiResult<Unit> {
        val result = safeApiCall { api.listHistory() }
        if (result is ApiResult.Success) {
            val completed = result.data.items.filter { it.status.lowercase() == "completed" }
            dao.replaceListType(
                OrderEntity.LIST_DRIVER_COMPLETED,
                completed.map { it.toEntity(OrderEntity.LIST_DRIVER_COMPLETED) }
            )
        }
        return result.toUnit()
    }

    // ── Optimistic local mutations ─────────────────────────────────────────

    /** Writes a single order to the given list-type bucket without hitting the network. */
    suspend fun optimisticUpsert(order: OrderRead, listType: String) {
        dao.upsertAll(listOf(order.toEntity(listType)))
    }

    /** Removes a single order from the given list-type bucket locally. */
    suspend fun optimisticRemove(orderId: Int, listType: String) {
        val current = dao.getByListType(listType)
        dao.replaceListType(listType, current.filter { it.orderId != orderId })
    }

    // ── Existing network-only operations (unchanged) ──────────────────────

    suspend fun createOrder(request: OrderCreateRequest): ApiResult<OrderRead> =
        safeApiCall { api.createOrder(request) }

    suspend fun listAvailable(limit: Int = 20, offset: Int = 0): ApiResult<PageResponse<OrderRead>> =
        safeApiCall { api.listAvailable(limit, offset) }

    suspend fun listHistory(limit: Int = 20, offset: Int = 0): ApiResult<PageResponse<OrderRead>> =
        safeApiCall { api.listHistory(limit, offset) }

    suspend fun listMyActive(): ApiResult<List<OrderRead>> =
        safeApiCall { api.listMyActive() }

    suspend fun getOrder(orderId: Int): ApiResult<OrderRead> =
        safeApiCall { api.getOrder(orderId) }

    suspend fun updateOrder(orderId: Int, request: OrderUpdateRequest): ApiResult<OrderRead> =
        safeApiCall { api.updateOrder(orderId, request) }

    suspend fun deleteOrder(orderId: Int): ApiResult<Unit> =
        safeApiCall { api.deleteOrder(orderId) }

    suspend fun acceptOrder(orderId: Int): ApiResult<OrderRead> =
        safeApiCall { api.acceptOrder(orderId) }

    suspend fun startOrder(orderId: Int): ApiResult<OrderRead> =
        safeApiCall { api.startOrder(orderId) }

    suspend fun pickupOrder(orderId: Int): ApiResult<OrderRead> =
        safeApiCall { api.pickupOrder(orderId) }

    suspend fun completeOrder(orderId: Int): ApiResult<OrderRead> {
        safeApiCall { api.pickupOrder(orderId) }
        return safeApiCall { api.completeOrder(orderId) }
    }

    suspend fun cancelOrder(orderId: Int, reason: String? = null): ApiResult<OrderRead> =
        safeApiCall { api.cancelOrder(orderId, OrderCancelRequest(reason)) }

    suspend fun submitRating(orderId: Int, score: Int, comment: String?): ApiResult<RatingRead> =
        safeApiCall { api.submitRating(orderId, RatingCreate(score, comment)) }

    suspend fun getOrderRating(orderId: Int): ApiResult<RatingRead> =
        safeApiCall { api.getOrderRating(orderId) }

    suspend fun submitRatingResponse(orderId: Int, response: String): ApiResult<RatingRead> =
        safeApiCall { api.submitRatingResponse(orderId, RatingResponseCreate(response)) }

    suspend fun deleteRatingResponse(orderId: Int): ApiResult<RatingRead> =
        safeApiCall { api.deleteRatingResponse(orderId) }
}

// ── Private helpers ────────────────────────────────────────────────────────

private fun <T> ApiResult<T>.toUnit(): ApiResult<Unit> = when (this) {
    is ApiResult.Success -> ApiResult.Success(Unit)
    is ApiResult.Error   -> this
}

package com.example.mobilefinalproject.repository

import android.content.Context
import com.example.mobilefinalproject.network.RetrofitClient
import com.example.mobilefinalproject.network.api.UserApi
import com.example.mobilefinalproject.network.dto.UserMe
import com.example.mobilefinalproject.network.dto.UserPublic
import com.example.mobilefinalproject.network.dto.UserUpdateRequest

class UserRepository(context: Context) {

    private val api: UserApi = RetrofitClient.createService(context)

    suspend fun getMe(): ApiResult<UserMe> = safeApiCall { api.getMe() }

    suspend fun updateMe(request: UserUpdateRequest): ApiResult<UserMe> =
        safeApiCall { api.updateMe(request) }

    suspend fun getUser(userId: Int): ApiResult<UserPublic> = safeApiCall { api.getUser(userId) }
}

package com.example.mobilefinalproject.repository

import android.content.Context
import com.example.mobilefinalproject.db.AppDatabase
import com.example.mobilefinalproject.db.toDto
import com.example.mobilefinalproject.db.toEntity
import com.example.mobilefinalproject.network.RetrofitClient
import com.example.mobilefinalproject.network.api.UserApi
import com.example.mobilefinalproject.network.dto.UserMe
import com.example.mobilefinalproject.network.dto.UserPublic
import com.example.mobilefinalproject.network.dto.UserUpdateRequest
import com.example.mobilefinalproject.session.UserSessionManager
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.map

class UserRepository(private val context: Context) {

    private val api: UserApi = RetrofitClient.createService(context)
    private val dao = AppDatabase.getInstance(context).userDao()

    // ── Reactive stream ────────────────────────────────────────────────────

    /**
     * Returns a [Flow] that emits the currently cached [UserMe] from Room.
     * It resolves the user's id from the active session; if no session exists it
     * falls back to the most recently cached row.
     */
    fun observeMe(): Flow<UserMe?> {
        val userId = UserSessionManager.getSession(context)?.userId?.toIntOrNull()
        return if (userId != null) {
            dao.observe(userId).map { it?.toDto() }
        } else {
            dao.observeLatest().map { it?.toDto() }
        }
    }

    // ── Network operations (always write result to Room cache) ─────────────

    suspend fun getMe(): ApiResult<UserMe> {
        val result = safeApiCall { api.getMe() }
        if (result is ApiResult.Success) {
            dao.upsert(result.data.toEntity())
        }
        return result
    }

    suspend fun updateMe(request: UserUpdateRequest): ApiResult<UserMe> {
        val result = safeApiCall { api.updateMe(request) }
        if (result is ApiResult.Success) {
            dao.upsert(result.data.toEntity())
        }
        return result
    }

    /** Writes a [UserMe] directly to the Room cache without hitting the network. */
    suspend fun cacheUser(user: UserMe) {
        dao.upsert(user.toEntity())
    }

    suspend fun getUser(userId: Int): ApiResult<UserPublic> =
        safeApiCall { api.getUser(userId) }

    // ── Cache management ──────────────────────────────────────────────────

    /** Clears the cached user data on logout. */
    suspend fun clearCache() = dao.deleteAll()
}

package com.example.mobilefinalproject.session

import android.content.Context
import androidx.core.content.edit
import com.example.mobilefinalproject.models.Customer
import com.example.mobilefinalproject.models.driver.Driver

object UserSessionManager {
    private const val PREFS_NAME = "user_session_prefs"
    private const val KEY_USER_TYPE = "user_type"
    private const val KEY_USER_ID = "user_id"
    private const val KEY_USER_NAME = "user_name"

    enum class UserType(val value: String) {
        DRIVER("driver"),
        CUSTOMER("customer");

        companion object {
            fun fromValue(value: String?): UserType? = entries.firstOrNull { it.value == value }
        }
    }

    data class UserSession(
        val userType: UserType,
        val userId: String,
        val fullName: String,
    )

    fun saveDriver(context: Context, driver: Driver) {
        saveSession(context, UserSession(UserType.DRIVER, driver.id, driver.fullName))
    }

    fun saveCustomer(context: Context, customer: Customer) {
        saveSession(context, UserSession(UserType.CUSTOMER, customer.id, customer.fullName))
    }

    fun saveSession(context: Context, session: UserSession) {
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE).edit {
            putString(KEY_USER_TYPE, session.userType.value)
            putString(KEY_USER_ID, session.userId)
            putString(KEY_USER_NAME, session.fullName)
        }
    }

    fun getSession(context: Context): UserSession? {
        val prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        val userType = UserType.fromValue(prefs.getString(KEY_USER_TYPE, null)) ?: return null
        val userId = prefs.getString(KEY_USER_ID, null)?.takeIf { it.isNotBlank() } ?: return null
        val fullName = prefs.getString(KEY_USER_NAME, null)?.takeIf { it.isNotBlank() } ?: return null
        return UserSession(userType, userId, fullName)
    }

    fun hasSession(context: Context): Boolean = getSession(context) != null

    fun clearSession(context: Context) {
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE).edit { clear() }
    }

    fun restoreDriver(context: Context): Driver? {
        val session = getSession(context) ?: return null
        return if (session.userType == UserType.DRIVER) {
            Driver(session.userId, session.fullName)
        } else {
            null
        }
    }

    fun restoreCustomer(context: Context): Customer? {
        val session = getSession(context) ?: return null
        return if (session.userType == UserType.CUSTOMER) {
            Customer(session.userId, session.fullName)
        } else {
            null
        }
    }
}

package com.example.mobilefinalproject.session

import android.content.Context
import androidx.core.content.edit

object UserSessionManager {
    private const val PREFS_NAME = "user_session_prefs"
    private const val KEY_USER_TYPE = "user_type"
    private const val KEY_USER_ID = "user_id"
    private const val KEY_USER_NAME = "user_name"
    private const val KEY_EMAIL = "email"
    private const val KEY_PHONE = "phone"
    private const val KEY_PROFILE_IMAGE_URL = "profile_image_url"

    enum class UserType(val value: String) {
        DRIVER("driver"),
        CUSTOMER("customer");

        companion object {
            fun fromValue(value: String?): UserType? = entries.firstOrNull { it.value == value }
        }
    }

    data class UserSession(
        val userType: UserType,
        val userId: String,
        val fullName: String,
        val email: String? = null,
        val phone: String? = null,
        val profileImageUrl: String? = null
    )

    fun saveSession(context: Context, session: UserSession) {
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE).edit {
            putString(KEY_USER_TYPE, session.userType.value)
            putString(KEY_USER_ID, session.userId)
            putString(KEY_USER_NAME, session.fullName)
            putString(KEY_EMAIL, session.email)
            putString(KEY_PHONE, session.phone)
            putString(KEY_PROFILE_IMAGE_URL, session.profileImageUrl)
        }
    }

    fun getSession(context: Context): UserSession? {
        val prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        val userType = UserType.fromValue(prefs.getString(KEY_USER_TYPE, null)) ?: return null
        val userId = prefs.getString(KEY_USER_ID, null)?.takeIf { it.isNotBlank() } ?: return null
        val fullName = prefs.getString(KEY_USER_NAME, null)?.takeIf { it.isNotBlank() } ?: return null
        return UserSession(
            userType = userType,
            userId = userId,
            fullName = fullName,
            email = prefs.getString(KEY_EMAIL, null),
            phone = prefs.getString(KEY_PHONE, null),
            profileImageUrl = prefs.getString(KEY_PROFILE_IMAGE_URL, null)
        )
    }

    fun hasSession(context: Context): Boolean = getSession(context) != null

    fun clearSession(context: Context) {
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE).edit { clear() }
    }
}

package com.example.mobilefinalproject.ui.customer

import android.net.Uri
import android.os.Bundle
import androidx.fragment.app.Fragment
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.activity.result.contract.ActivityResultContracts
import androidx.activity.result.PickVisualMediaRequest
import androidx.core.content.ContextCompat
import android.content.pm.PackageManager
import androidx.fragment.app.activityViewModels
import androidx.navigation.fragment.findNavController
import com.example.mobilefinalproject.BuildConfig
import com.example.mobilefinalproject.R
import com.example.mobilefinalproject.databinding.FragmentCustomerEditProfileBinding
import com.example.mobilefinalproject.ui.common.LoadingOverlayController
import com.example.mobilefinalproject.viewmodels.CustomerViewModel
import com.squareup.picasso.Picasso

class CustomerEditProfileFragment : Fragment() {

    private val customerViewModel: CustomerViewModel by activityViewModels()
    private var binding: FragmentCustomerEditProfileBinding? = null
    private var loadingOverlay: LoadingOverlayController? = null
    private var selectedImageUri: Uri? = null

    private val imagePickerLauncher = registerForActivityResult(
        ActivityResultContracts.PickVisualMedia()
    ) { uri ->
        uri?.let {
            selectedImageUri = it
            binding?.customerEditProfileImageView?.let { imageView ->
                Picasso.get().load(selectedImageUri).into(imageView)
            }
        }
    }

    private val permissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        if (isGranted) {
            imagePickerLauncher.launch(
                PickVisualMediaRequest(ActivityResultContracts.PickVisualMedia.ImageOnly)
            )
        }
    }

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        binding = FragmentCustomerEditProfileBinding.inflate(inflater, container, false)
        loadingOverlay = LoadingOverlayController(
            requireContext(),
            requireActivity().findViewById(android.R.id.content)
        )
        return binding?.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        customerViewModel.userMe.observe(viewLifecycleOwner) { user ->
            if (user != null) {
                binding?.customerEditProfileFullNameEditText?.setText(user.fullName)
                // Show the user's email in the read-only field instead of numeric ID
                binding?.customerEditProfileEmailEditText?.setText(user.email)

                // Load profile image from server
                if (user.profileImageUrl != null) {
                    val profilePath = if (user.profileImageUrl.startsWith("/")) {
                        user.profileImageUrl.substring(1)
                    } else {
                        user.profileImageUrl
                    }
                    val imageUrl = "${BuildConfig.BASE_URL}${profilePath}"
                    binding?.customerEditProfileImageView?.let { imageView ->
                        Picasso.get()
                            .load(imageUrl)
                            .placeholder(R.drawable.ic_person)
                            .error(R.drawable.ic_person)
                            .into(imageView)
                    }
                }
            }
        }

        customerViewModel.loading.observe(viewLifecycleOwner) { loading ->
            if (loading) loadingOverlay?.show() else loadingOverlay?.hide()
        }

        binding?.customerEditProfileSaveButton?.setOnClickListener { saveProfile() }
        binding?.customerEditProfileCancelButton?.setOnClickListener { findNavController().navigateUp() }
        binding?.customerEditProfileChangePictureButton?.setOnClickListener { checkAndRequestGalleryPermission() }
    }

    private fun checkAndRequestGalleryPermission() {
        val permission = android.Manifest.permission.READ_MEDIA_IMAGES
        when {
            ContextCompat.checkSelfPermission(requireContext(), permission) == PackageManager.PERMISSION_GRANTED ->
                imagePickerLauncher.launch(PickVisualMediaRequest(ActivityResultContracts.PickVisualMedia.ImageOnly))
            else -> permissionLauncher.launch(permission)
        }
    }

    private fun saveProfile() {
        val binding = binding ?: return
        val updatedFullName = binding.customerEditProfileFullNameEditText.text.toString().trim()

        if (updatedFullName.isEmpty()) {
            binding.customerEditProfileFullNameEditText.error = "Full name cannot be empty"
            return
        }

        customerViewModel.updateProfile(fullName = updatedFullName, imageUri = selectedImageUri, onSuccess = {
            findNavController().navigateUp()
        })
    }

    override fun onDestroyView() {
        super.onDestroyView()
        loadingOverlay?.detach()
        loadingOverlay = null
        binding = null
    }
}

package com.example.mobilefinalproject.ui.customer

import android.net.Uri
import android.os.Bundle
import androidx.fragment.app.Fragment
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.activity.result.contract.ActivityResultContracts
import androidx.activity.result.PickVisualMediaRequest
import androidx.core.content.ContextCompat
import android.content.pm.PackageManager
import androidx.fragment.app.activityViewModels
import androidx.lifecycle.lifecycleScope
import androidx.navigation.fragment.findNavController
import com.example.mobilefinalproject.BuildConfig
import com.example.mobilefinalproject.R
import com.example.mobilefinalproject.cache.ImageCacheManager
import com.example.mobilefinalproject.databinding.FragmentCustomerEditProfileBinding
import com.example.mobilefinalproject.ui.common.LoadingOverlayController
import com.example.mobilefinalproject.viewmodels.CustomerViewModel
import com.squareup.picasso.Picasso
import kotlinx.coroutines.launch

class CustomerEditProfileFragment : Fragment() {

    private val customerViewModel: CustomerViewModel by activityViewModels()
    private var binding: FragmentCustomerEditProfileBinding? = null
    private var loadingOverlay: LoadingOverlayController? = null
    private var imageCacheManager: ImageCacheManager? = null
    private var selectedImageUri: Uri? = null

    private val imagePickerLauncher = registerForActivityResult(
        ActivityResultContracts.PickVisualMedia()
    ) { uri ->
        uri?.let {
            selectedImageUri = it
            // Local URI preview — no caching needed, use Picasso directly.
            binding?.customerEditProfileImageView?.let { imageView ->
                Picasso.get().load(selectedImageUri).into(imageView)
            }
        }
    }

    private val permissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        if (isGranted) {
            imagePickerLauncher.launch(
                PickVisualMediaRequest(ActivityResultContracts.PickVisualMedia.ImageOnly)
            )
        }
    }

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        binding = FragmentCustomerEditProfileBinding.inflate(inflater, container, false)
        loadingOverlay = LoadingOverlayController(
            requireContext(),
            requireActivity().findViewById(android.R.id.content)
        )
        imageCacheManager = ImageCacheManager(requireContext().applicationContext)
        return binding?.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        customerViewModel.userMe.observe(viewLifecycleOwner) { user ->
            if (user != null) {
                binding?.customerEditProfileFullNameEditText?.setText(user.fullName)
                binding?.customerEditProfileEmailEditText?.setText(user.email)

                // Don't reload the image if the user already picked a new one from gallery.
                if (selectedImageUri == null && user.profileImageUrl != null) {
                    val profilePath = if (user.profileImageUrl.startsWith("/")) {
                        user.profileImageUrl.substring(1)
                    } else {
                        user.profileImageUrl
                    }
                    val imageUrl = "${BuildConfig.BASE_URL}${profilePath}"
                    val imageView = binding?.customerEditProfileImageView ?: return@observe
                    val cacheManager = imageCacheManager ?: return@observe
                    viewLifecycleOwner.lifecycleScope.launch {
                        cacheManager.loadInto(
                            url = imageUrl,
                            imageView = imageView,
                            placeholderRes = R.drawable.ic_person
                        )
                    }
                }
            }
        }

        customerViewModel.loading.observe(viewLifecycleOwner) { loading ->
            if (loading) loadingOverlay?.show() else loadingOverlay?.hide()
        }

        binding?.customerEditProfileSaveButton?.setOnClickListener { saveProfile() }
        binding?.customerEditProfileCancelButton?.setOnClickListener { findNavController().navigateUp() }
        binding?.customerEditProfileChangePictureButton?.setOnClickListener { checkAndRequestGalleryPermission() }
    }

    private fun checkAndRequestGalleryPermission() {
        val permission = android.Manifest.permission.READ_MEDIA_IMAGES
        when {
            ContextCompat.checkSelfPermission(requireContext(), permission) == PackageManager.PERMISSION_GRANTED ->
                imagePickerLauncher.launch(PickVisualMediaRequest(ActivityResultContracts.PickVisualMedia.ImageOnly))
            else -> permissionLauncher.launch(permission)
        }
    }

    private fun saveProfile() {
        val binding = binding ?: return
        val updatedFullName = binding.customerEditProfileFullNameEditText.text.toString().trim()

        if (updatedFullName.isEmpty()) {
            binding.customerEditProfileFullNameEditText.error = "Full name cannot be empty"
            return
        }

        customerViewModel.updateProfile(fullName = updatedFullName, imageUri = selectedImageUri, onSuccess = {
            findNavController().navigateUp()
        })
    }

    override fun onDestroyView() {
        super.onDestroyView()
        loadingOverlay?.detach()
        loadingOverlay = null
        imageCacheManager = null
        binding = null
    }
}

