    private val _pendingDeliveries = MutableLiveData<List<Delivery>>()
    val pendingDeliveries: LiveData<List<Delivery>> = _pendingDeliveries

    private val _customerDeliveries = MutableLiveData<List<Delivery>>()
    val customerDeliveries: LiveData<List<Delivery>> = _customerDeliveries

    fun getDeliveriesByCustomer(customerId: String): List<Delivery> {
        return _deliveries.value?.filter { it.customerId == customerId } ?: emptyList()
    }
    fun setDeliveries(deliveries: List<Delivery>) {
        _deliveries.value = deliveries
    }

    fun setActiveDeliveries(activeDeliveries: List<Delivery>) {
        _activeDeliveries.value = activeDeliveries
    }

    fun setCompletedDeliveries(completedDeliveries: List<Delivery>) {
        _completedDeliveries.value = completedDeliveries
    }

    fun setCustomerDeliveries(customerDeliveries: List<Delivery>) {
        _customerDeliveries.value = customerDeliveries
    }

    fun setPendingDeliveries(pendingDeliveries: List<Delivery>) {
        _pendingDeliveries.value = pendingDeliveries
    }


    fun addDelivery(delivery: Delivery) {
        val currentList = _deliveries.value?.toMutableList() ?: mutableListOf()
        currentList.add(delivery)
        _deliveries.value = currentList
    }

    fun removeDelivery(delivery: Delivery) {
        val currentList = _deliveries.value?.toMutableList() ?: mutableListOf()
        currentList.remove(delivery)
        _deliveries.value = currentList
    }

    fun updateDelivery(delivery: Delivery) {
        val currentList = _deliveries.value?.toMutableList() ?: mutableListOf()
        val index = currentList.indexOfFirst { it.id == delivery.id }
        if (index != -1) {
            currentList[index] = delivery
            _deliveries.value = currentList
        }
    }
}

package com.example.mobilefinalproject.viewmodels

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import androidx.lifecycle.viewModelScope
import com.example.mobilefinalproject.network.dto.DriverProfile
import com.example.mobilefinalproject.network.dto.UserMe
import com.example.mobilefinalproject.network.dto.UserUpdateRequest
import com.example.mobilefinalproject.repository.ApiResult
import com.example.mobilefinalproject.repository.DriverRepository
import com.example.mobilefinalproject.repository.UserRepository
import com.example.mobilefinalproject.repository.UploadRepository
import android.net.Uri
import com.example.mobilefinalproject.session.UserSessionManager
import kotlinx.coroutines.launch

class DriverViewModel(application: Application) : AndroidViewModel(application) {

    private val repo = UserRepository(application)
    private val driverRepo = DriverRepository(application)
    private val uploadRepo = UploadRepository(application)

    private val _driverProfile = MutableLiveData<DriverProfile?>()
    val driverProfile: LiveData<DriverProfile?> = _driverProfile

    private val _userMe = MutableLiveData<UserMe?>()
    val userMe: LiveData<UserMe?> = _userMe

    private val _error = MutableLiveData<String?>(null)
    val error: LiveData<String?> = _error

    private val _loading = MutableLiveData(false)
    val loading: LiveData<Boolean> = _loading

    // ── Convenience accessors ─────────────────────────────────────────────────
    val driverName: String get() = _userMe.value?.fullName ?: ""
    val driverId: Int get() = _userMe.value?.id ?: 0

    fun loadMe() {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.getMe()) {
                is ApiResult.Success -> _userMe.value = result.data
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    fun setUserMe(user: UserMe) {
        _userMe.value = user
    }

    fun updateProfile(
        fullName: String? = null,
        phone: String? = null,
        imageUri: Uri? = null,
        onSuccess: (() -> Unit)? = null
    ) {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.updateMe(UserUpdateRequest(fullName = fullName, phone = phone))) {
                is ApiResult.Success -> {
                    _userMe.value = result.data
                    val ctx = getApplication<Application>()
                    UserSessionManager.getSession(ctx)?.let { session ->
                        UserSessionManager.saveSession(ctx, session.copy(fullName = result.data.fullName))
                    }

                    if (imageUri != null) {
                        val hadImageBefore = _userMe.value?.profileImageUrl != null
                        when (val uploadResult = uploadRepo.uploadProfileImage(imageUri, existing = hadImageBefore)) {
                            is ApiResult.Success -> {
                                loadMe()
                                onSuccess?.invoke()
                            }
                            is ApiResult.Error -> _error.value = uploadResult.message
                        }
                    } else {
                        onSuccess?.invoke()
                    }
                }
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    /** Set the driver's availability status on the backend. */
    fun updateDriverStatus(status: String) {
        viewModelScope.launch {
            when (val result = driverRepo.updateStatus(status)) {
                is ApiResult.Success -> _driverProfile.value = result.data
                is ApiResult.Error -> _error.value = result.message
            }
        }
    }

    /** Marks driver as available — call when entering the Finder screen. */
    fun setAvailable() = updateDriverStatus("available")

    /**
     * Fetches the current driver profile and sets status to "available"
     * only if the driver is not currently "busy" (i.e. has no active order).
     */
    fun setAvailableIfNotBusy() {
        viewModelScope.launch {
            when (val result = driverRepo.getMe()) {
                is ApiResult.Success -> {
                    _driverProfile.value = result.data
                    if (result.data.status != "busy") {
                        updateDriverStatus("available")
                    }
                }
                is ApiResult.Error -> {
                    // If we can't fetch the profile, default to setting available
                    updateDriverStatus("available")
                }
            }
        }
    }

    /** Marks driver as offline — call on logout. */
    fun setOffline() = updateDriverStatus("offline")

    /**
     * Sets the driver offline via the API *before* invoking [onDone],
     * but only if the driver is not currently "busy" with an active order.
     * Ensures the auth token is still valid when the request is made.
     */
    fun setOfflineAndLogout(onDone: () -> Unit) {
        viewModelScope.launch {
            val currentStatus = when (val result = driverRepo.getMe()) {
                is ApiResult.Success -> result.data.status
                is ApiResult.Error -> _driverProfile.value?.status
            }
            if (currentStatus != "busy") {
                driverRepo.updateStatus("offline") // best-effort; ignore errors
            }
            onDone()
        }
    }

    fun clearDriver() {
        _userMe.value = null
    }

    fun clearError() {
        _error.value = null
    }
}

package com.example.mobilefinalproject.viewmodels

import android.app.Application
import android.net.Uri
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import androidx.lifecycle.asLiveData
import androidx.lifecycle.viewModelScope
import com.example.mobilefinalproject.network.dto.DriverProfile
import com.example.mobilefinalproject.network.dto.UserMe
import com.example.mobilefinalproject.network.dto.UserUpdateRequest
import com.example.mobilefinalproject.repository.ApiResult
import com.example.mobilefinalproject.repository.DriverRepository
import com.example.mobilefinalproject.repository.UploadRepository
import com.example.mobilefinalproject.repository.UserRepository
import com.example.mobilefinalproject.session.UserSessionManager
import kotlinx.coroutines.launch

class DriverViewModel(application: Application) : AndroidViewModel(application) {

    private val repo = UserRepository(application)
    private val driverRepo = DriverRepository(application)
    private val uploadRepo = UploadRepository(application)

    // ── Room-backed reactive LiveData ─────────────────────────────────────

    /** Emits the cached [DriverProfile] from Room; updates automatically after any network sync. */
    val driverProfile: LiveData<DriverProfile?> =
        driverRepo.observeMe().asLiveData(viewModelScope.coroutineContext)

    /** Emits the cached [UserMe] from Room (common user fields like name / photo). */
    val userMe: LiveData<UserMe?> =
        repo.observeMe().asLiveData(viewModelScope.coroutineContext)

    // ── Local-only state ──────────────────────────────────────────────────

    private val _error = MutableLiveData<String?>(null)
    val error: LiveData<String?> = _error

    private val _loading = MutableLiveData(false)
    val loading: LiveData<Boolean> = _loading

    val driverName: String get() = userMe.value?.fullName ?: ""
    val driverId: Int get() = userMe.value?.id ?: 0

    // ── Operations ────────────────────────────────────────────────────────

    /** Fetches user profile from the network and updates the Room cache. */
    fun loadMe() {
        viewModelScope.launch {
            _loading.value = true
            val result = repo.getMe()
            if (result is ApiResult.Error) _error.value = result.message
            _loading.value = false
        }
    }

    fun setUserMe(user: UserMe) {
        viewModelScope.launch { repo.cacheUser(user) }
    }

    fun updateProfile(
        fullName: String? = null,
        phone: String? = null,
        imageUri: Uri? = null,
        onSuccess: (() -> Unit)? = null
    ) {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.updateMe(UserUpdateRequest(fullName = fullName, phone = phone))) {
                is ApiResult.Success -> {
                    val ctx = getApplication<Application>()
                    UserSessionManager.getSession(ctx)?.let { session ->
                        UserSessionManager.saveSession(ctx, session.copy(fullName = result.data.fullName))
                    }
                    if (imageUri != null) {
                        val hadImageBefore = result.data.profileImageUrl != null
                        when (val uploadResult = uploadRepo.uploadProfileImage(imageUri, existing = hadImageBefore)) {
                            is ApiResult.Success -> {
                                repo.getMe()
                                onSuccess?.invoke()
                            }
                            is ApiResult.Error -> _error.value = uploadResult.message
                        }
                    } else {
                        onSuccess?.invoke()
                    }
                }
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    fun updateDriverStatus(status: String) {
        viewModelScope.launch {
            when (val result = driverRepo.updateStatus(status)) {
                is ApiResult.Success -> Unit   // Room cache is updated inside the repo
                is ApiResult.Error -> _error.value = result.message
            }
        }
    }

    fun setAvailable() = updateDriverStatus("available")

    fun setAvailableIfNotBusy() {
        viewModelScope.launch {
            when (val result = driverRepo.getMe()) {
                is ApiResult.Success -> {
                    if (result.data.status != "busy") updateDriverStatus("available")
                }
                is ApiResult.Error -> updateDriverStatus("available")
            }
        }
    }

    fun setOffline() = updateDriverStatus("offline")

    fun setOfflineAndLogout(onDone: () -> Unit) {
        viewModelScope.launch {
            val currentStatus = when (val result = driverRepo.getMe()) {
                is ApiResult.Success -> result.data.status
                is ApiResult.Error   -> driverProfile.value?.status
            }
            if (currentStatus != "busy") driverRepo.updateStatus("offline")
            onDone()
        }
    }

    fun clearDriver() {
        viewModelScope.launch {
            repo.clearCache()
            driverRepo.clearCache()
        }
    }

    fun clearError() {
        _error.value = null
    }
}

package com.example.mobilefinalproject.viewmodels

import android.app.Application
import android.net.Uri
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import androidx.lifecycle.viewModelScope
import com.example.mobilefinalproject.network.dto.OrderCreateRequest
import com.example.mobilefinalproject.network.dto.OrderRead
import com.example.mobilefinalproject.network.dto.OrderUpdateRequest
import com.example.mobilefinalproject.repository.ApiResult
import com.example.mobilefinalproject.repository.OrderRepository
import com.example.mobilefinalproject.repository.UploadRepository
import kotlinx.coroutines.launch

class OrderViewModel(application: Application) : AndroidViewModel(application) {

    private val repo = OrderRepository(application)
    private val uploadRepo = UploadRepository(application)

    // ── Customer: my orders ──────────────────────────────────────────────────
    private val _customerOrders = MutableLiveData<List<OrderRead>>(emptyList())
    val customerOrders: LiveData<List<OrderRead>> = _customerOrders

    // ── Driver: active orders assigned to me ────────────────────────────────
    private val _activeOrders = MutableLiveData<List<OrderRead>>(emptyList())
    val activeOrders: LiveData<List<OrderRead>> = _activeOrders

    // ── Driver: completed orders ─────────────────────────────────────────────
    private val _completedOrders = MutableLiveData<List<OrderRead>>(emptyList())
    val completedOrders: LiveData<List<OrderRead>> = _completedOrders

    // ── Driver Finder: pending (unassigned) orders ───────────────────────────
    private val _pendingOrders = MutableLiveData<List<OrderRead>>(emptyList())
    val pendingOrders: LiveData<List<OrderRead>> = _pendingOrders

    // ── Selected order (for map marker / detail dialog) ──────────────────────
    private val _selectedOrder = MutableLiveData<OrderRead?>(null)
    val selectedOrder: LiveData<OrderRead?> = _selectedOrder

    // ── Error / toast messages ────────────────────────────────────────────────
    private val _error = MutableLiveData<String?>(null)
    val error: LiveData<String?> = _error

    // ── Loading ───────────────────────────────────────────────────────────────
    private val _loading = MutableLiveData(false)
    val loading: LiveData<Boolean> = _loading

    fun selectOrder(order: OrderRead?) {
        _selectedOrder.value = order
    }

    private fun List<OrderRead>.filterByStatus(vararg allowedStatuses: String): List<OrderRead> {
        val allowed = allowedStatuses.map { it.lowercase() }.toSet()
        return filter { it.status.lowercase() in allowed }
    }

    private fun isOrderAlreadyTracked(list: List<OrderRead>, orderId: Int): Boolean =
        list.any { it.id == orderId }

    // ─────────────────────────────────────────────────────────────────────────
    // Customer operations
    // ─────────────────────────────────────────────────────────────────────────

    /** Load the customer's own order history (all statuses). */
    fun loadMyOrders() {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.listHistory()) {
                is ApiResult.Success -> _customerOrders.value = result.data.items
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    fun createOrder(
        request: OrderCreateRequest,
        imageUri: Uri? = null,
        onSuccess: ((OrderRead) -> Unit)? = null
    ) {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.createOrder(request)) {
                is ApiResult.Success -> {
                    val createdOrder = result.data

                    if (imageUri != null) {
                        when (val uploadResult = uploadRepo.uploadOrderImage(createdOrder.id, imageUri)) {
                            is ApiResult.Success -> Unit
                            is ApiResult.Error -> _error.value = uploadResult.message
                        }
                    }

                    loadMyOrders()
                    onSuccess?.invoke(createdOrder)
                }
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    fun updateOrder(
        orderId: Int,
        request: OrderUpdateRequest,
        imageUri: android.net.Uri? = null,
        hadImageBefore: Boolean = false,
        onSuccess: (() -> Unit)? = null
    ) {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.updateOrder(orderId, request)) {
                is ApiResult.Success -> {
                    // If a new image was selected, upload it (POST/PUT depending on previous state)
                    if (imageUri != null) {
                        when (val uploadResult = uploadRepo.uploadOrderImage(orderId, imageUri, existing = hadImageBefore)) {
                            is ApiResult.Success -> Unit
                            is ApiResult.Error -> _error.value = uploadResult.message
                        }
                    }

                    loadMyOrders()
                    onSuccess?.invoke()
                }
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    fun cancelOrder(orderId: Int, reason: String? = null, onSuccess: (() -> Unit)? = null) {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.cancelOrder(orderId, reason)) {
                is ApiResult.Success -> {
                    loadMyOrders()
                    onSuccess?.invoke()
                }
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Driver operations
    // ─────────────────────────────────────────────────────────────────────────

    /** Load all orders currently assigned to the driver (accepted/in-progress/picked-up). */
    fun loadActiveDriverOrders() {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.listMyActive()) {
                is ApiResult.Success -> _activeOrders.value = result.data.filterByStatus(
                    "accepted",
                    "in_progress"
                )
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    fun loadCompletedDriverOrders() {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.listHistory()) {
                is ApiResult.Success -> _completedOrders.value = result.data.items.filterByStatus(
                    "completed"
                )
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    /** Load pending (unassigned) orders visible to the driver for the Finder screen. */
    fun loadPendingOrders() {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.listAvailable()) {
                is ApiResult.Success -> _pendingOrders.value = result.data.items.filterByStatus(
                    "pending"
                )
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    fun acceptOrder(orderId: Int, onSuccess: (() -> Unit)? = null) {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.acceptOrder(orderId)) {
                is ApiResult.Success -> {
                    loadPendingOrders()
                    loadActiveDriverOrders()
                    onSuccess?.invoke()
                }
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    fun startOrder(orderId: Int, onSuccess: (() -> Unit)? = null) {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.startOrder(orderId)) {
                is ApiResult.Success -> {
                    loadActiveDriverOrders()
                    onSuccess?.invoke()
                }
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    @Suppress("unused")
    fun pickupOrder(orderId: Int, onSuccess: (() -> Unit)? = null) {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.pickupOrder(orderId)) {
                is ApiResult.Success -> {
                    loadActiveDriverOrders()
                    onSuccess?.invoke()
                }
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    @Suppress("unused")
    fun completeOrder(orderId: Int, onSuccess: (() -> Unit)? = null) {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.completeOrder(orderId)) {
                is ApiResult.Success -> {
                    loadActiveDriverOrders()
                    loadCompletedDriverOrders()
                    loadPendingOrders()
                    onSuccess?.invoke()
                }
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    /**
     * Optimistically mark an order as completed in the local lists so the UI updates immediately.
     * Then call the API to persist the change; on failure we revert the optimistic update and
     * surface an error message.
     */
    fun completeOrderOptimistic(order: OrderRead) {
        // Keep snapshots so we can restore them if the API call fails.
        val previousActive = _activeOrders.value.orEmpty()
        val previousCompleted = _completedOrders.value.orEmpty()
        val previousPending = _pendingOrders.value.orEmpty()

        // Remove from active list immediately and add to completed list
        val currentActive = previousActive.toMutableList()
        currentActive.removeAll { it.id == order.id }
        _activeOrders.value = currentActive.filterByStatus("accepted", "in_progress")

        val completed = previousCompleted.toMutableList()
        if (!isOrderAlreadyTracked(completed, order.id)) {
            // Insert a copy with status set to completed so UI shows it correctly
            completed.add(0, order.copy(status = "completed"))
        }
        _completedOrders.value = completed.filterByStatus("completed")

        val pending = previousPending.toMutableList()
        pending.removeAll { it.id == order.id }
        _pendingOrders.value = pending.filterByStatus("pending")

        // Persist on background; revert if API call fails
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.completeOrder(order.id)) {
                is ApiResult.Success -> {
                    // Refresh from server to ensure canonical state
                    loadActiveDriverOrders()
                    loadCompletedDriverOrders()
                    loadPendingOrders()
                }
                is ApiResult.Error -> {
                    // Revert optimistic update
                    _activeOrders.value = previousActive.filterByStatus("accepted", "in_progress")
                    _completedOrders.value = previousCompleted.filterByStatus("completed")
                    _pendingOrders.value = previousPending.filterByStatus("pending")
                    _error.value = result.message
                }
            }
            _loading.value = false
        }
    }

    fun clearError() {
        _error.value = null
    }
}

package com.example.mobilefinalproject.viewmodels

import android.app.Application
import android.net.Uri
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import androidx.lifecycle.asLiveData
import androidx.lifecycle.viewModelScope
import com.example.mobilefinalproject.db.entity.OrderEntity
import com.example.mobilefinalproject.network.dto.OrderCreateRequest
import com.example.mobilefinalproject.network.dto.OrderRead
import com.example.mobilefinalproject.network.dto.OrderUpdateRequest
import com.example.mobilefinalproject.repository.ApiResult
import com.example.mobilefinalproject.repository.OrderRepository
import com.example.mobilefinalproject.repository.UploadRepository
import kotlinx.coroutines.launch

class OrderViewModel(application: Application) : AndroidViewModel(application) {

    private val repo = OrderRepository(application)
    private val uploadRepo = UploadRepository(application)

    // ── Room-backed reactive LiveData (auto-updates when DB changes) ──────

    /** Customer's full order history, served from Room cache. */
    val customerOrders: LiveData<List<OrderRead>> =
        repo.observeCustomerOrders().asLiveData(viewModelScope.coroutineContext)

    /** Driver: active (accepted / in-progress) orders, served from Room cache. */
    val activeOrders: LiveData<List<OrderRead>> =
        repo.observeActiveDriverOrders().asLiveData(viewModelScope.coroutineContext)

    /** Driver: completed orders, served from Room cache. */
    val completedOrders: LiveData<List<OrderRead>> =
        repo.observeCompletedDriverOrders().asLiveData(viewModelScope.coroutineContext)

    /** Driver Finder: pending (unassigned) orders, served from Room cache. */
    val pendingOrders: LiveData<List<OrderRead>> =
        repo.observePendingOrders().asLiveData(viewModelScope.coroutineContext)

    // ── Local-only state (not persisted) ───────────────────────────────────

    private val _selectedOrder = MutableLiveData<OrderRead?>(null)
    val selectedOrder: LiveData<OrderRead?> = _selectedOrder

    private val _error = MutableLiveData<String?>(null)
    val error: LiveData<String?> = _error

    private val _loading = MutableLiveData(false)
    val loading: LiveData<Boolean> = _loading

    fun selectOrder(order: OrderRead?) {
        _selectedOrder.value = order
    }

    // ── Customer operations ────────────────────────────────────────────────

    /** Triggers a network refresh; Room cache updates automatically → LiveData notifies UI. */
    fun loadMyOrders() {
        viewModelScope.launch {
            _loading.value = true
            val result = repo.refreshCustomerOrders()
            if (result is ApiResult.Error) _error.value = result.message
            _loading.value = false
        }
    }

    fun createOrder(
        request: OrderCreateRequest,
        imageUri: Uri? = null,
        onSuccess: ((OrderRead) -> Unit)? = null
    ) {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.createOrder(request)) {
                is ApiResult.Success -> {
                    val createdOrder = result.data
                    if (imageUri != null) {
                        when (val uploadResult = uploadRepo.uploadOrderImage(createdOrder.id, imageUri)) {
                            is ApiResult.Success -> Unit
                            is ApiResult.Error -> _error.value = uploadResult.message
                        }
                    }
                    // Refresh cache so the new order appears in the list
                    repo.refreshCustomerOrders()
                    onSuccess?.invoke(createdOrder)
                }
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    fun updateOrder(
        orderId: Int,
        request: OrderUpdateRequest,
        imageUri: android.net.Uri? = null,
        hadImageBefore: Boolean = false,
        onSuccess: (() -> Unit)? = null
    ) {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.updateOrder(orderId, request)) {
                is ApiResult.Success -> {
                    if (imageUri != null) {
                        when (val uploadResult = uploadRepo.uploadOrderImage(orderId, imageUri, existing = hadImageBefore)) {
                            is ApiResult.Success -> Unit
                            is ApiResult.Error -> _error.value = uploadResult.message
                        }
                    }
                    repo.refreshCustomerOrders()
                    onSuccess?.invoke()
                }
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    fun cancelOrder(orderId: Int, reason: String? = null, onSuccess: (() -> Unit)? = null) {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.cancelOrder(orderId, reason)) {
                is ApiResult.Success -> {
                    repo.refreshCustomerOrders()
                    onSuccess?.invoke()
                }
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    // ── Driver operations ─────────────────────────────────────────────────

    fun loadActiveDriverOrders() {
        viewModelScope.launch {
            _loading.value = true
            val result = repo.refreshActiveDriverOrders()
            if (result is ApiResult.Error) _error.value = result.message
            _loading.value = false
        }
    }

    fun loadCompletedDriverOrders() {
        viewModelScope.launch {
            _loading.value = true
            val result = repo.refreshCompletedDriverOrders()
            if (result is ApiResult.Error) _error.value = result.message
            _loading.value = false
        }
    }

    fun loadPendingOrders() {
        viewModelScope.launch {
            _loading.value = true
            val result = repo.refreshPendingOrders()
            if (result is ApiResult.Error) _error.value = result.message
            _loading.value = false
        }
    }

    fun acceptOrder(orderId: Int, onSuccess: (() -> Unit)? = null) {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.acceptOrder(orderId)) {
                is ApiResult.Success -> {
                    repo.refreshPendingOrders()
                    repo.refreshActiveDriverOrders()
                    onSuccess?.invoke()
                }
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    fun startOrder(orderId: Int, onSuccess: (() -> Unit)? = null) {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.startOrder(orderId)) {
                is ApiResult.Success -> {
                    repo.refreshActiveDriverOrders()
                    onSuccess?.invoke()
                }
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    @Suppress("unused")
    fun pickupOrder(orderId: Int, onSuccess: (() -> Unit)? = null) {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.pickupOrder(orderId)) {
                is ApiResult.Success -> {
                    repo.refreshActiveDriverOrders()
                    onSuccess?.invoke()
                }
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    @Suppress("unused")
    fun completeOrder(orderId: Int, onSuccess: (() -> Unit)? = null) {
        viewModelScope.launch {
            _loading.value = true
            when (val result = repo.completeOrder(orderId)) {
                is ApiResult.Success -> {
                    repo.refreshActiveDriverOrders()
                    repo.refreshCompletedDriverOrders()
                    repo.refreshPendingOrders()
                    onSuccess?.invoke()
                }
                is ApiResult.Error -> _error.value = result.message
            }
            _loading.value = false
        }
    }

    /**
     * Optimistically marks an order as completed in the local Room cache so the UI
     * updates immediately, then calls the API to persist the change; reverts on failure.
     */
    fun completeOrderOptimistic(order: OrderRead) {
        viewModelScope.launch {
            // Optimistic DB writes — Room notifies LiveData observers instantly
            repo.optimisticRemove(order.id, OrderEntity.LIST_DRIVER_ACTIVE)
            repo.optimisticUpsert(order.copy(status = "completed"), OrderEntity.LIST_DRIVER_COMPLETED)
            repo.optimisticRemove(order.id, OrderEntity.LIST_DRIVER_PENDING)

            _loading.value = true
            when (val result = repo.completeOrder(order.id)) {
                is ApiResult.Success -> {
                    // Sync authoritative state from server
                    repo.refreshActiveDriverOrders()
                    repo.refreshCompletedDriverOrders()
                    repo.refreshPendingOrders()
                }
                is ApiResult.Error -> {
                    // Revert optimistic changes
                    repo.optimisticUpsert(order, OrderEntity.LIST_DRIVER_ACTIVE)
                    repo.optimisticRemove(order.id, OrderEntity.LIST_DRIVER_COMPLETED)
                    _error.value = result.message
                }
            }
            _loading.value = false
        }
    }

    fun clearError() {
        _error.value = null
    }
}

